import { Component, OnInit } from '@angular/core';
import { UnitmasterService } from '../../setup/unitmaster/unitmaster.service';
import { Subscription } from 'rxjs';
import { MatDialog } from '@angular/material/dialog';
import { NotificationsComponent } from './notifications/notifications.component';

@Component({
  selector: 'ux-dashboard-analytics',
  templateUrl: './dashboard-analytics.component.html',
  styleUrls: ['./dashboard-analytics.component.scss']
})
export class DashboardAnalyticsComponent implements OnInit {
  unitSubscription: Subscription;
  unitnotifications_list = [];

  constructor(
    private unitService: UnitmasterService,
    private dialog: MatDialog
  ) {

  }

  ngOnInit(): void {
    this.unitService.getAllUnitNotifications();
    this.unitSubscription = this.unitService.unitnotificationsChanged
      .subscribe(
        (units: any[]) => {
          this.unitnotifications_list = units;
          console.log(this.unitnotifications_list)

        }
      );
  }

  onOpenNotifications(notificationinfo: any) {
    this.dialog.open(NotificationsComponent, {
      height: '70%',
      width: '70%',
      data: {
        notificationinfo: notificationinfo
      }
    }).afterClosed().subscribe((data: any) => {
      
    });
  }

}
